{
  "day": "1",
  "heading": "Drive from Bhakti Nagar Police Station to Yuksom",
  "sub_heading": "Drive Distance: 140 km | Drive Duration: 6-7 hours | Pickup point: Bhakti Nagar Police Station, Siliguri | Pickup time: 9.00 AM",
  "details": "The cost is Rs.1800/- (additional 5% GST) per trekker (one-way). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek. \n\nNote: In cases of bad weather/ road conditions, the vehicle might have to go through Darjeeling, which will increase the total cost."
}

{
  "day": "2",
  "heading": "Trek from Yuksom to Sachen",
  "sub_heading": "Trek Distance: 7.50 km | Trek Duration: 5.5 hours | Altitude Gain: 5,840 ft to 7,400 ft",
  "details": "Trek gradient is moderate-difficult. Gradual climb for 2.5 hours after which the trail becomes steeper up to Sachen. Carry 2 litres of water from Yuksom. You will cross streams intermittently where you can refill your water bottles."
}

{
  "day": "3",
  "heading": "Sachen to Tshoka via Bakhim",
  "sub_heading": "Trek Distance: 6.50 km | Trek Duration: 5.5 hours | Altitude Gain: 7,400 ft to 9,790 ft via 8,640 ft",
  "details": "Moderate gradient with initial rolling terrain through the forests and 40 minutes of ascent from Bakhim in a series of long switchbacks after which the trail eases off into a gradual climb. Carry sufficient water from Sachen."
}

{
  "day": "4",
  "heading": "Tshoka to Dzongri via Phedang",
  "sub_heading": "Trek Distance: 8.40 km | Trek Duration: 8-9 hours | Altitude Gain: 9,790 ft to 13,190 ft via 12,105 ft",
  "details": "Today is going to be a difficult day. It starts with 30 minutes of steep climb followed by a gradual ascent, after which the trail again climbs steeply for 20 minutes to reach Phedang. 1-hour ascent from here followed by a gentle descent brings you to Dzongri."
}

{
  "day": "5",
  "heading": "Dzongri to Dzongri Top and back. Acclimatization day at Dzongri",
  "sub_heading": "Trek Distance: 2 km | Trek Duration: 2.5-3 hour | Altitude Gain and Loss: 13,190 ft to 13,670 ft and back to 13,190 ft",
  "details": "The day starts with a climb to Dzongri Top. Dzongri Top at 13,670 ft, is the highest point from where you get 180-degree panoramic view of the mighty peaks such as Kakthong, Rothang, Kabru South, Kabru North, Kabru Dome, Kanchenjunga, Pandim, and the Lama Lamini peaks."
}

{
  "day": "6",
  "heading": "Dzongri to Thansing via Kokchurang",
  "sub_heading": "Trek Distance: 6.55 km | Trek Duration: 6 hours | Altitude Loss and Gain: 13,190 ft to 12,910 ft via 12,090 ft",
  "details": "Gentle descent for about 2 hours followed by a steep descent to Kokchurang. Continuous ascent from here to Thansing. Carry 2 litres of water from Dzongri. The only water source on the way where you can refill your water bottles will be at Kokchurang."
}

{
  "day": "7",
  "heading": "Thansing to View Point 1 via Samiti Lake; and back to Thansing",
  "sub_heading": "Trek Distance: 16 km | Trek Duration: 12-14 hours | Altitude Gain and Loss: 12,910 ft to 15,100 ft via 14,120 ft; and back to 12,910 ft",
  "details": "The longest day of your trek. The distance is long, followed by continuous ascent to reach View Point 1. Stay well hydrated and carry 2 litres of water before beginning the summit climb as well as before the descent to Thansing. There will be no water source on either stretch."
}

{
  "day": "8",
  "heading": "Thansing to Tshoka via Kokchurang and Phedang",
  "sub_heading": "Trek Distance: 13 km | Trek Duration: 9 hours | Altitude Loss: 12,910 ft to 9,790 ft via 12,090 ft and 12,105 ft",
  "details": "Continuous ascent till Kokchurang, followed by relatively flat trail to Phedang for about 4 hours, and a steep descent to Tshoka. Stay well hydrated and carry 2 litres of water from Thansing since there is no water source on the trail today."
}

{
  "day": "9",
  "heading": "Tshoka to Yuksom via Bakhim and Sachen",
  "sub_heading": "Trek Distance: 13 km | Trek Duration: 6 hours | Altitude Loss: 9,790 ft to 5,840 ft via 8,640 ft and 7,400 ft",
  "details": "Continuous descent to Sachen, followed by an undulating trail to Yuksom. Carry sufficient water from Tshoka. You will cross a few streams where you can refill your water bottles."
}

{
  "day": "10",
  "heading": "Drive back from Yuksom to Bhakti Nagar Police Station",
  "sub_heading": "Drive Distance: 170 km | Drive Duration: 7-8 hours | Drop off point: Bhakti Nagar Police Station, Siliguri | Drop off time: 5 PM",
  "details": "Transport will be arranged by Indiahikes. The cost is Rs.1800/- (additional 5% GST) per trekker (one-way). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek.\nPlease note: The distance between campsites may vary by 100 meters depending the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons."
}
